package graph

// CRUD resolvers for Post. The signatures here must match what gqlgen
// generates from graphql/schema.graphql — if you change the schema, run
// `make gql` and update these methods accordingly.

import (
	"context"
	"fmt"

	"github.com/google/uuid"
)

func (r *queryResolver) ListPosts(ctx context.Context, page *int, pageSize *int) (*PostsPage, error) {
	p := 1
	ps := 20
	if page != nil {
		p = *page
	}
	if pageSize != nil {
		ps = *pageSize
	}
	if p < 1 {
		p = 1
	}
	if ps < 1 || ps > 100 {
		ps = 20
	}

	items := make([]*Post, 0)
	r.Resolver.postStore.Range(func(_, v any) bool {
		if row, ok := v.(*Post); ok {
			items = append(items, row)
		}
		return true
	})
	start := (p - 1) * ps
	if start > len(items) {
		start = len(items)
	}
	end := start + ps
	if end > len(items) {
		end = len(items)
	}
	return &PostsPage{
		Items:    items[start:end],
		Total:    len(items),
		Page:     p,
		PageSize: ps,
	}, nil
}

func (r *queryResolver) GetPost(ctx context.Context, id string) (*Post, error) {
	if v, ok := r.Resolver.postStore.Load(id); ok {
		return v.(*Post), nil
	}
	return nil, nil
}

func (r *mutationResolver) CreatePost(ctx context.Context, input CreatePostInput) (*Post, error) {
	row := mapCreatePost(input)
	if row.Id == "" {
		row.Id = uuid.NewString()
	}
	r.Resolver.postStore.Store(row.Id, row)
	return row, nil
}

func (r *mutationResolver) UpdatePost(ctx context.Context, input UpdatePostInput) (*Post, error) {
	if _, ok := r.Resolver.postStore.Load(input.Id); !ok {
		return nil, fmt.Errorf("Post %s not found", input.Id)
	}
	row := mapUpdatePost(input)
	r.Resolver.postStore.Store(row.Id, row)
	return row, nil
}

func (r *mutationResolver) DeletePost(ctx context.Context, id string) (bool, error) {
	_, existed := r.Resolver.postStore.LoadAndDelete(id)
	return existed, nil
}

// mapCreatePost / mapUpdatePost convert generated input types to the
// model struct. Stub implementations — gqlgen will generate the input types
// alongside the model, so adapt these accordingly after `make gql`.
func mapCreatePost(input CreatePostInput) *Post {
	row := &Post{}
	_ = input
	return row
}

func mapUpdatePost(input UpdatePostInput) *Post {
	row := &Post{}
	_ = input
	return row
}

