)

var ts *httptest.Server

func TestMain(m *testing.M) {
	cfg := config.New() // reads from env; defaults work for tests
	srv := server.New(cfg, slog.Default())
	ts = httptest.NewServer(srv.Handler())
	code := m.Run()
	ts.Close()
	os.Exit(code)
